from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
from elasticsearch.exceptions import ElasticsearchException
import os
import re
from functools import lru_cache

app = Flask(__name__)

ES_URL = os.getenv("ELASTICSEARCH_URL", "http://localhost:9200")
ES_INDEX = os.getenv("ELASTICSEARCH_INDEX", "products")

es = Elasticsearch(
    ES_URL,
    request_timeout=2,
    max_retries=2,
    retry_on_timeout=True,
    http_compress=True,
)

def _sanitize_query(q: str) -> str:
    q = (q or "").strip()
    q = re.sub(r"\s+", " ", q)
    return q

@lru_cache(maxsize=1024)
def _search_products_cached(query: str):
    body = {
        "size": 20,
        "_source": ["id", "name", "price", "image_url", "brand", "category"],
        "query": {
            "multi_match": {
                "query": query,
                "fields": ["name^4", "brand^2", "category^2", "description"],
                "type": "best_fields",
                "operator": "and",
                "fuzziness": "AUTO"
            }
        },
        "sort": [
            "_score",
            {"popularity": "desc"}
        ]
    }
    return es.search(index=ES_INDEX, body=body)

@app.route("/api/search", methods=["GET"])
def search_products():
    q = _sanitize_query(request.args.get("q", ""))
    if not q:
        return jsonify({"error": "Missing required query parameter: q"}), 400

    try:
        resp = _search_products_cached(q)
        hits = [
            {
                "id": hit["_source"].get("id"),
                "name": hit["_source"].get("name"),
                "price": hit["_source"].get("price"),
                "image_url": hit["_source"].get("image_url"),
                "brand": hit["_source"].get("brand"),
                "category": hit["_source"].get("category"),
                "score": hit.get("_score"),
            }
            for hit in resp.get("hits", {}).get("hits", [])
        ]
        return jsonify({"query": q, "count": len(hits), "results": hits}), 200
    except ElasticsearchException:
        return jsonify({"error": "Search service unavailable"}), 503
    except Exception:
        return jsonify({"error": "Internal server error"}), 500

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.getenv("PORT", "5000")))